class SDEvaluator extends Evaluator<SDEnv> implements SDASTVisitor<JamVal> {

  SDEvaluator(SDEnv env) { super(env); }

  /*  EvalVisitor methods for evaluating SDASTs. */
  public SDASTVisitor<JamVal> newEvalVisitor(SDEnv env) { return new SDEvaluator(env); }

  public JamVal forSDPair(SDPair p)  { return env.lookup(p); }

  public JamVal forSMap(SMap sm) { return new SDClosure(sm, this); }

  public JamVal forSLet(SLet sl) {
    /* Extract rhss from sl */
    SDAST[] rhss = sl.rhss();
    int n = rhss.length;

    /* Evaluate all rhs expressions to build the values array */
    JamVal[] vals = new JamVal[n];
    for (int i = 0; i < n; i++) {
      vals[i] = rhss[i].accept(this);
    }

    /* Construct newEnv for Let body with the evaluated values */
    SDEnv newEnv = env.cons(vals);
    SDASTVisitor<JamVal> newEvalVisitor = newEvalVisitor(newEnv);
    return sl.body().accept(newEvalVisitor);
  }

  public JamVal forSLetRec(SLetRec slr) {
    /* Extract rhss from slr */
    SDAST[] rhss = slr.rhss();
    int n = rhss.length;

    /* Create dummy values array (will be filled in with closures) */
    JamVal[] vals = new JamVal[n];
    for (int i = 0; i < n; i++) {
      vals[i] = null;  // dummy value, will be fixed up
    }

    /* Construct newEnv with the dummy values */
    SDEnv newEnv = env.cons(vals);
    SDASTVisitor<JamVal> newEvalVisitor = newEvalVisitor(newEnv);

    /* Fix up the values by evaluating rhss in the new environment */
    for (int i = 0; i < n; i++) {
      vals[i] = rhss[i].accept(newEvalVisitor);
    }

    return slr.body().accept(newEvalVisitor);
  }

  /* Methods that are never invoked in the evaluation of well-formed SDASTs */
  public JamVal forVariable(Variable host) { return forDefault(host); }
  public JamVal forMap(Map host) { return forDefault(host); }
  public JamVal forLet(Let host) { return forDefault(host); }
  public JamVal forLetRec(LetRec host) { return forDefault(host); }
}

